import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { getMyPlayrooms, updatePlayroom } from "../services/playroomService";
import { useAuth } from "../context/AuthContext";
import PlayroomForm from "../components/PlayroomForm";
import "../styles/ManagePlayroom.css";

const ManagePlayroom = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [playroom, setPlayroom] = useState(null);
  const [loading, setLoading] = useState(true);
  const [editing, setEditing] = useState(false);
  const [formData, setFormData] = useState({});
  const [message, setMessage] = useState("");

  useEffect(() => {
    loadPlayroom();
  }, []);

  const loadPlayroom = async () => {
    setLoading(true);
    const result = await getMyPlayrooms();
    if (result.success && result.data.length > 0) {
      const myPlayroom = result.data[0];
      setPlayroom(myPlayroom);
      setFormData({
        naziv: myPlayroom.naziv,
        adresa: myPlayroom.adresa,
        grad: myPlayroom.grad,
        opis: myPlayroom.opis,
        kontaktTelefon: myPlayroom.kontaktTelefon,
        kontaktEmail: myPlayroom.kontaktEmail,
        kapacitet: {
          deca: myPlayroom.kapacitet?.deca || "",
          roditelji: myPlayroom.kapacitet?.roditelji || "",
        },
        osnovnaCena: myPlayroom.osnovnaCena || "",
        cene: myPlayroom.cene || [],
        paketi: myPlayroom.paketi || [],
        dodatneUsluge: myPlayroom.dodatneUsluge || [],
        besplatnePogodnosti: myPlayroom.besplatnePogodnosti || [],
      });
    } else {
      navigate("/create-playroom");
    }
    setLoading(false);
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    if (name.includes(".")) {
      const [parent, child] = name.split(".");
      setFormData((prev) => ({
        ...prev,
        [parent]: {
          ...prev[parent],
          [child]: value,
        },
      }));
    } else {
      setFormData((prev) => ({
        ...prev,
        [name]: value,
      }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Pripremi podatke za slanje
    const updateData = {
      ...formData,
      kapacitet: {
        deca: parseInt(formData.kapacitet.deca),
        roditelji: formData.kapacitet.roditelji
          ? parseInt(formData.kapacitet.roditelji)
          : 0,
      },
      osnovnaCena: parseInt(formData.osnovnaCena),
    };

    const result = await updatePlayroom(playroom._id, updateData);
    if (result.success) {
      setMessage("Podaci su uspešno ažurirani");
      setEditing(false);
      loadPlayroom();
      setTimeout(() => setMessage(""), 3000);
    } else {
      alert(result.error);
    }
  };

  if (loading) {
    return <div className="container loading">Učitavanje...</div>;
  }

  if (!playroom) {
    return null;
  }

  return (
    <div className="container manage-playroom-page">
      <h1>🏢 Moja igraonica</h1>

      {message && <div className="success-message">{message}</div>}

      <div className="playroom-status">
        <div
          className={`status-badge ${playroom.verifikovan ? "verified" : "pending"}`}
        >
          {playroom.verifikovan ? "✅ Verifikovano" : "⏳ Čeka verifikaciju"}
        </div>
      </div>

      {!editing ? (
        <div className="playroom-details-card">
          <div className="playroom-details-header">
            <h2>{playroom.naziv}</h2>
            <button className="btn-edit" onClick={() => setEditing(true)}>
              ✏️ Uredi podatke
            </button>
          </div>

          <div className="details-grid">
            <div className="detail-item">
              <label>📍 Adresa</label>
              <p>
                {playroom.adresa}, {playroom.grad}
              </p>
            </div>
            <div className="detail-item">
              <label>📞 Telefon</label>
              <p>{playroom.kontaktTelefon}</p>
            </div>
            <div className="detail-item">
              <label>📧 Email</label>
              <p>{playroom.kontaktEmail}</p>
            </div>
            <div className="detail-item">
              <label>👶 Kapacitet dece</label>
              <p>{playroom.kapacitet?.deca || 0} dece</p>
            </div>
            <div className="detail-item">
              <label>👨‍👩‍👧 Kapacitet roditelja</label>
              <p>
                {playroom.kapacitet?.roditelji
                  ? `${playroom.kapacitet.roditelji} roditelja`
                  : "Neograničeno"}
              </p>
            </div>
            <div className="detail-item">
              <label>💰 Osnovna cena</label>
              <p>{playroom.osnovnaCena} RSD / dete</p>
            </div>

            {/* Ostale cene */}
            {playroom.cene && playroom.cene.length > 0 && (
              <div className="detail-item full-width">
                <label>💰 Ostale cene</label>
                <div className="items-list">
                  {playroom.cene.map((item, idx) => (
                    <div key={idx} className="item-display">
                      <span>
                        <strong>{item.naziv}</strong>: {item.cena} RSD
                      </span>
                      {item.opis && (
                        <span className="item-opis">({item.opis})</span>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Paketi */}
            {playroom.paketi && playroom.paketi.length > 0 && (
              <div className="detail-item full-width">
                <label>🎁 Paketi</label>
                <div className="items-list">
                  {playroom.paketi.map((item, idx) => (
                    <div key={idx} className="item-display">
                      <span>
                        <strong>{item.naziv}</strong>: {item.cena} RSD
                      </span>
                      {item.opis && (
                        <span className="item-opis">({item.opis})</span>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Dodatne usluge */}
            {playroom.dodatneUsluge && playroom.dodatneUsluge.length > 0 && (
              <div className="detail-item full-width">
                <label>🎪 Dodatne usluge</label>
                <div className="items-list">
                  {playroom.dodatneUsluge.map((item, idx) => (
                    <div key={idx} className="item-display">
                      <span>
                        <strong>{item.naziv}</strong>: {item.cena} RSD
                      </span>
                      <span className="item-type">
                        {item.tip === "po_osobi" ? "(po osobi)" : "(fiksno)"}
                      </span>
                      {item.opis && (
                        <span className="item-opis">({item.opis})</span>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Besplatne pogodnosti */}
            {playroom.besplatnePogodnosti &&
              playroom.besplatnePogodnosti.length > 0 && (
                <div className="detail-item full-width">
                  <label>✨ Besplatne pogodnosti</label>
                  <div className="free-features-list">
                    {playroom.besplatnePogodnosti.map((item, idx) => (
                      <span key={idx} className="free-badge">
                        ✓ {item}
                      </span>
                    ))}
                  </div>
                </div>
              )}

            <div className="detail-item full-width">
              <label>📝 Opis</label>
              <p>{playroom.opis}</p>
            </div>
          </div>
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="edit-form">
          <h2>Uredi podatke</h2>

          <div className="form-group">
            <label>Naziv igraonice *</label>
            <input
              type="text"
              name="naziv"
              value={formData.naziv || ""}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Adresa *</label>
              <input
                type="text"
                name="adresa"
                value={formData.adresa || ""}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <label>Grad *</label>
              <input
                type="text"
                name="grad"
                value={formData.grad || ""}
                onChange={handleChange}
                required
              />
            </div>
          </div>

          <div className="form-group">
            <label>Opis *</label>
            <textarea
              name="opis"
              rows="4"
              value={formData.opis || ""}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Kontakt telefon *</label>
              <input
                type="tel"
                name="kontaktTelefon"
                value={formData.kontaktTelefon || ""}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <label>Kontakt email *</label>
              <input
                type="email"
                name="kontaktEmail"
                value={formData.kontaktEmail || ""}
                onChange={handleChange}
                required
              />
            </div>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Kapacitet dece *</label>
              <input
                type="number"
                name="kapacitet.deca"
                value={formData.kapacitet?.deca || ""}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <label>Kapacitet roditelja (opciono)</label>
              <input
                type="number"
                name="kapacitet.roditelji"
                value={formData.kapacitet?.roditelji || ""}
                onChange={handleChange}
                placeholder="0 = neograničeno"
              />
            </div>
          </div>

          <div className="form-group">
            <label>Osnovna cena po detetu (RSD) *</label>
            <input
              type="number"
              name="osnovnaCena"
              value={formData.osnovnaCena || ""}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-buttons">
            <button
              type="button"
              className="btn-cancel"
              onClick={() => setEditing(false)}
            >
              Otkaži
            </button>
            <button type="submit" className="btn-save">
              Sačuvaj izmene
            </button>
          </div>
        </form>
      )}

      <div className="playroom-actions">
        <button
          className="btn-secondary"
          onClick={() => navigate("/manage-slots")}
        >
          📅 Upravljanje terminima
        </button>
      </div>
    </div>
  );
};

export default ManagePlayroom;
